import anthropic

client = anthropic.Anthropic()

code_tools = [
    {
        "name": "execute_python",
        "description": (
            "Execute Python code and return stdout and stderr. "
            "Use this to compute results, analyze data, and test your code. "
            "Imports are available. Standard library is available. "
            "Results are NOT persistent between calls."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {
                    "type": "string",
                    "description": "Python code to execute. Use print() to output results.",
                },
            },
            "required": ["code"],
        },
    },
]

def run_coding_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]
    system = (
        "You are a Python coding assistant. "
        "Use the execute_python tool to write and test code. "
        "When code fails, read the error and fix it. "
        "When the output is correct, report the result."
    )
    while True:
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=2048,
            system=system,
            tools=code_tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return "Done."

        tool_results = []
        for block in response.content:
            if block.type == "tool_use" and block.name == "execute_python":
                result = execute_python(block.input["code"])
                output = result["stdout"]
                if result["stderr"]:
                    output += f"\nSTDERR: {result['stderr']}"
                if result["timed_out"]:
                    output = "ERROR: Execution timed out."
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output or "(no output)",
                })
        messages.append({"role": "user", "content": tool_results})

answer = run_coding_agent(
    "Write Python code to find all prime numbers up to 100 and compute their sum."
)
print(answer)

import anthropic, json

client = anthropic.Anthropic()

structured_tool = [
    {
        "name": "run_analysis",
        "description": (
            "Run Python data analysis code. "
            "Your code MUST end with: print(json.dumps(result)) "
            "where result is a dict with your findings. "
            "Import json at the top of your code."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {"type": "string", "description": "Python code that prints a JSON dict"},
            },
            "required": ["code"],
        },
    },
]

def run_structured_agent(task: str) -> dict:
    messages = [{"role": "user", "content": task}]
    system = (
        "You are a data analysis assistant. "
        "Use run_analysis to compute results. "
        "Your code must end with print(json.dumps(result)) where result is a dict."
    )
    while True:
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=2048,
            system=system,
            tools=structured_tool,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return {}  # no structured output produced

        tool_results = []
        for block in response.content:
            if block.type == "tool_use" and block.name == "run_analysis":
                exec_result = execute_python(block.input["code"])
                raw_output = exec_result["stdout"].strip()
                # Try to parse JSON from the last line
                parsed = {}
                for line in reversed(raw_output.splitlines()):
                    try:
                        parsed = json.loads(line)
                        break
                    except json.JSONDecodeError:
                        continue
                if parsed:
                    return parsed  # return structured result immediately
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": raw_output or exec_result.get("stderr", "(no output)"),
                })
        if tool_results:
            messages.append({"role": "user", "content": tool_results})

result = run_structured_agent(
    "Analyze the numbers 1 through 20: compute the sum, mean, max, and count of evens."
)
print(result)
# {'sum': 210, 'mean': 10.5, 'max': 20, 'even_count': 10}
